output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?opponent ?opponentLabel WHERE {
  ?game wdt:P585 '2023-11-23' ^^ xsd:date ; wdt:P710 wd:Q204862 ; wdt:P710 ?opponent .
  FILTER(?opponent != wd:Q204862)
  OPTIONAL {
    ?opponent rdfs:label ?opponentLabel
    FILTER(LANG(?opponentLabel) = 'en')
  }
}

args.sparql:
SELECT ?opponent ?opponentLabel ?date WHERE { {
    ?game wdt:P6052 wd:Q204862; 
           wdt:P6053 ?opponent; 
           wdt:P585 ?date.
  }
  UNION
  {
    ?game wdt:P6053 wd:Q204862; 
           wdt:P6052 ?opponent; 
           wdt:P585 ?date.
  }
  FILTER (MONTH(?date) = 11)
  FILTER (DAY(?date) >= 22)
  FILTER (DAY(?date) <= 28)
  ?opponent wdt:P31 wd:Q473972.
  OPTIONAL { ?opponent rdfs:label ?opponentLabel FILTER (lang(?opponentLabel) = "en") }
} ORDER BY DESC(?date) LIMIT 1

SELECT ?opponent ?opponentLabel ?date WHERE { 
  ?game wdt:P710 wd:Q204862;
        wdt:P710 ?opponent;
        wdt:P585 ?date.
  FILTER(?opponent != wd:Q204862)
  FILTER(MONTH(?date) = 11)
  FILTER(DAY(?date) >= 22)
  FILTER(DAY(?date) <= 28)
  OPTIONAL { ?opponent rdfs:label ?opponentLabel FILTER (lang(?opponentLabel) = "en") }
} ORDER BY DESC(?date) LIMIT 1
